target.css:
:root {
  --card-bg: #ffffff;
  --header-bg: #4f46e5;
  --badge-bg: #f59e0b;
  --badge-text: #ffffff;
  --plan-name-color: #ffffff;
  --price-color: #ffffff;
  --currency-color: #c7d2fe;
  --period-color: #c7d2fe;
  --desc-color: #c7d2fe;
  --feature-included-color: #1e1b4b;
  --feature-excluded-color: #9ca3af;
  --feature-included-dot: #4f46e5;
  --feature-excluded-dot: #d1d5db;
  --divider-color: #e5e7eb;
  --cta-bg: #4f46e5;
  --cta-text: #ffffff;
  --note-color: #9ca3af;
  --card-border: #e5e7eb;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 20px;
  width: 300px;
  overflow: hidden;
}

.plan-header {
  background: var(--header-bg);
  padding: 28px 28px 24px;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 8px;
}

.plan-badge {
  background: var(--badge-bg);
  color: var(--badge-text);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.1em;
  padding: 4px 10px;
  border-radius: 20px;
}

.plan-name {
  color: var(--plan-name-color);
  font-size: 22px;
  font-weight: 700;
  margin: 4px 0 0;
  line-height: 1;
}

.plan-price {
  display: flex;
  align-items: flex-start;
  gap: 2px;
  margin-top: 4px;
}

.currency {
  color: var(--currency-color);
  font-size: 18px;
  font-weight: 600;
  margin-top: 6px;
  line-height: 1;
}

.amount {
  color: var(--price-color);
  font-size: 52px;
  font-weight: 800;
  line-height: 1;
}

.period {
  color: var(--period-color);
  font-size: 16px;
  font-weight: 500;
  align-self: flex-end;
  margin-bottom: 6px;
}

.plan-desc {
  color: var(--desc-color);
  font-size: 13px;
  line-height: 1.5;
  margin: 0;
}

.feature-list {
  list-style: none;
  margin: 0;
  padding: 16px 28px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  border-bottom: 1px solid var(--divider-color);
}

.feature-item {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 14px;
  font-weight: 500;
}

.feature-item::before {
  content: '';
  display: block;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}

.feature-item.included {
  color: var(--feature-included-color);
}

.feature-item.included::before {
  background: var(--feature-included-dot);
}

.feature-item.excluded {
  color: var(--feature-excluded-color);
  text-decoration: line-through;
}

.feature-item.excluded::before {
  background: var(--feature-excluded-dot);
}

.cta-btn {
  display: block;
  width: calc(100% - 56px);
  margin: 20px 28px 12px;
  background: var(--cta-bg);
  color: var(--cta-text);
  border: none;
  border-radius: 10px;
  padding: 14px 0;
  font-size: 15px;
  font-weight: 700;
  cursor: pointer;
  letter-spacing: 0.02em;
}

.plan-note {
  text-align: center;
  color: var(--note-color);
  font-size: 12px;
  margin: 0 0 20px;
}

